import { Component } from '@angular/core';
import { SelectTabService } from 'src/app/services/select-tab.service';

@Component({
  selector: 'app-tabs',
  templateUrl: 'tabs.page.html',
  styleUrls: ['tabs.page.scss']
})
export class TabsPage {

  constructor(
    public selectTab:SelectTabService
  ) {}
  
  tabChange(ev){
    this.selectTab.selectTab.next(ev.tab);
  }

}
